#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
const int N=1000005;
int n,m,st[N][30],lg[N];
il int qu(int l,int r)
{
	if(l>r)return -1;
	int k=lg[r-l+1];
	return max(st[l][k],st[r-(1<<k)+1][k]);
}
signed main(void)
{
	n=read();
	FOR(i,1,n)
	{
		int v=read();
		st[i][0]=v;
		st[i+n][0]=v;
		st[i+n+n][0]=v;
	}
	if(n==1)
	{
		read();
		write(-1);
		pc(' ');
		return 0;
	}
	m=n+n+n;
	lg[1]=0;
	FOR(i,2,m)lg[i]=lg[i>>1]+1;
	FOR(j,1,lg[m])
	{
		FOR(i,1,m-(1<<j)+1)
		{
			st[i][j]=max(st[i][j-1],st[i+(1<<(j-1))][j-1]);
		}
	}
	FOR(i,1,n)
	{
		int b=read();
		int p=i+n;
		if(qu(p+1,p+n-1)<b)
		{
			write(-1);
			pc(' ');
			continue;
		}
		int l=1,r=n/2,ans=-1;
		wh(l<=r)
		{
			int md=mid;
			int mx=max(qu(p-md,p-1),qu(p+1,p+md));
			if(mx>=b)
			{
				ans=md;
				r=md-1;
			}
			else
			{
				l=md+1;
			}
		}
		if(ans==-1)write(-1);
		else write(ans);
		pc(' ');
	}
	return false;
}
